var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"현재, 그로니아 파레마\\n반군 점령지역","JPN":"現在、グロニア パレマ\\n反軍占領地域","ENG":"Present\\nParema, Gronia\\nRebel-held territory","TWN":"現在，格羅尼亞 波雷馬\\n叛軍佔領地區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>주민들에게 알린다. 30분 후 식량 배급을 실시할 예정이다.</color>","JPN":"<color=#ffd34c>住民に告げる。30分後食料の配給を行う予定だ。</color>","ENG":"<color=#ffd34c>Notice to residents. Food distribution will take place in half an hour.</color>","TWN":"<color=#ffd34c>居民注意，30分鐘後將發放糧食。</color>"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>배급 장소로 올 때는 반드시 통행증을 지참할 것. 반복한다…….</color>","JPN":"<color=#ffd34c>配給所に来るときは必ず通行証を持ってくるように。繰り返す……</color>","ENG":"<color=#ffd34c>Bring your pass when you come to the distribution center. I repeat...</color>","TWN":"<color=#ffd34c>移動至配給地點時務必攜帶通行證。再重複一次……</color>"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"제길, 우리 먹고 뒈질 것도 없는 마당에 이게 무슨 짓이야.","JPN":"ちくしょう、俺たちの分もないのに何をやってるんだ。","ENG":"Damn it, there's not that much food left for us. Why the hell are they giving this much out?","TWN":"可惡！我們自己吃都不夠了，這是在幹嘛！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"하여튼 우리 대장님은 사람이 너무 물러서 문제야.","JPN":"まったく、俺らの隊長は甘すぎるんだよ。","ENG":"Our captain is too soft. It's a problem.","TWN":"我們隊長的問題就是心太軟！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"그게 좋은 거지. 강경파 놈들처럼 욕 먹을 필요 없잖아.","JPN":"それがいいんだろう。強硬派の連中みたいに悪口言われずに済むじゃないか。","ENG":"Come on man, it's a good thing. No need to get a mouthful like those bastards from the hardliners.","TWN":"這是好事吧？要是隊長跟強硬派的一樣，那我們的日子會很難過吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"이거로 주둥이나 막고 있어. 운전 방해하지 말고.","JPN":"これ飲んで黙ってろ。運転の邪魔すんじゃねぇ。","ENG":"Here, drink some of this and don't distract me while I'm driving.","TWN":"拿這個把你的嘴堵起來！別妨礙我開車！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L11_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"오, 술이잖아? 어디서 이런 귀한 걸 구했대?","JPN":"お、酒じゃねぇか？　こんな貴重なものをどこで手に入れたんだ？","ENG":"Oh, whiskey? How did you acquire something so valuable?","TWN":"嗯？這是酒？這麼珍貴的東西，你是從哪弄來的？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"조카가 보급계거든. 후방의 윗분들은 술이고 여자고 넘치니까 한 병 정도 슬쩍해도 몰라.","JPN":"甥っ子が補給係でさ。後方のお偉方は酒も女も持て余してるから、一本ぐらいこっそり盗んでもわかりゃしねぇのさ。","ENG":"My nephew has connections with the supply chain. The higher ups in the back have so much whiskey and women, no one notices if you take one bottle.","TWN":"我的姪子是配給部的，後勤的那些長官最不缺的就是酒和女人，偷走一瓶他們不會發現啦～"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"쳇…. 고생은 우리가 다 하는데 윗분들은 뒷구멍으로 다 꿍쳐 놓네.","JPN":"ちぇっ……苦労は俺たちにさせて、おいしいとこは全部お偉方が持っていくんだな。","ENG":"Tchh... We are working so hard while the higher ups just mess around in the back.","TWN":"嘖…我們在前方衝鋒陷陣，那些高官卻在後方喝酒玩女人？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"흐흐, 그러게나 말이야. 기회 봐서 정부군에 투항이나 할까?","JPN":"へへ、そうだな。機を見て政府軍に投降でもするか？","ENG":"Heh, that's what I'm saying, man. You want to take this opportunity and surrender to the government forces?","TWN":"呵呵，說的沒錯！我看有機會的話，乾脆向政府軍投誠吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"보안국 놈들이 가만두겠냐? 분명 아는 거 다 불라고 쥐어짠 다음……","JPN":"保安局の連中が放っとくわけねぇだろ？　絶対知ってること全部吐けって……","ENG":"You think the National Security wouldn't catch us? Bro, if they caught us we’d be—","TWN":"安全局的傢伙會放過我們嗎？一定會對我們嚴刑拷問，然後……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"젠장, 아까운 술 다 쏟았네!","JPN":"おい、酒零したじゃねぇか！","ENG":"Damn it, I spilled the whiskey!","TWN":"該死！這麼珍貴的酒都打翻了啦！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"갑자기 브레이크는 왜 밟아? 술 냄새 맡고 취했냐?","JPN":"なにいきなりブレーキ踏んでんだ？　酒の匂いで酔ったか？","ENG":"Why the hell did you have to slam on the brakes all of a sudden? Are you drunk just from smelling it?","TWN":"幹嘛突然緊急剎車？你是聞到酒的味道也會醉是不是？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"정신 차리고 총이나 챙겨, 등신아. 저 앞에 여자 안 보이냐?","JPN":"ふざけないで銃を持て、タコ。あそこに女がいるだろ？","ENG":"Pull yourself together and ready your gun, idiot. Can't you see the girl in front of us?","TWN":"少在那邊嘴砲，把槍拿好！你沒看到前面有個女的嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"뭐? 여자?","JPN":"はあ？　女？","ENG":"What? A girl?","TWN":"什麼女的？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"후우, 이 도시도 난장판이 다 됐네.","JPN":"ふう、この街もひどいありさまだね。","ENG":"Whew... Looks like this city is all messed up too.","TWN":"呼～這裡也是一團糟呢！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"이러면 길은 지나가는 시민 분들한테 물어 봐야 하나?","JPN":"この感じじゃあ、道は通りすがりの市民に聞いた方がいいかな？","ENG":"Well, I guess I should ask a citizen passing by now, shouldn’t I?","TWN":"看來只能抓路人來問囉？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"거기 여자! 쏴 버리기 전에 손 들고 뒤로 돌아서!","JPN":"そこの女！　撃たれたくなけりゃ、手上げて後ろを向け！","ENG":"You there! Turn around and put your hands up or I’ll shoot!","TWN":"喂！手舉高轉過身去，否則我要開槍囉！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L29_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"아까부터 수상하게 두리번거리던데, 정부군이 보낸 스파이냐?","JPN":"さっきから怪しげにきょろきょろしてたな、政府軍のスパイか？","ENG":"What are you doing walking around all suspicious like...You a spy sent by the government forces?","TWN":"從剛剛就很可疑地在那邊左顧右盼的，你是政府軍派來的間諜吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"정부군이라뇨. 설마요.","JPN":"政府軍だなんて、まさか。","ENG":"The government forces? No way.","TWN":"什麼政府軍，才不是咧～"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"마침 와 주셔서 고마워요. 오랜만에 왔더니 다 폐허로 변해서 길을 헤매던 참이었거든요.","JPN":"ちょうどいいところに来てくれてありがとう。久しぶりに来たら廃墟になっていて、道に迷っていたんです。","ENG":"Anyways, I’m so glad you’re here. Everything is in ruins and I’ve just been wandering around for so long.","TWN":"你們來得正好，我太久沒來這裡，沒想到竟然全都變成了廢墟，現在整個找不到路。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"으응……?","JPN":"んん……？","ENG":"...H-huh?","TWN":"找不到路……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"웃옷 안주머니에 여기 대장님이 주신 통행증이 있어요. 직접 꺼내서 확인해 보세요.","JPN":"上着の懐にここの隊長がくださった通行証があります。取り出して確認してください。","ENG":"There’s a pass from the captain inside my coat pocket. Go ahead, you can take it out yourselves and take a look.","TWN":"我上衣口袋裡有隊長給我的通行證，你們可以直接掏出來看。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"지, 직접 말이지? 그럴까?","JPN":"ちょ、直接だな？　そうするか？","ENG":"Ta... Take a look our ourselves? Shall we?","TWN":"直…直接掏出來嗎？要嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"미친 소리. 수류탄이라도 숨겨 뒀을지 어떻게 알고.","JPN":"何言ってんだ。手榴弾が隠されているかもしれないぞ。","ENG":"Don’t be stupid, bro. She could be hiding a grenade in there for all we know.","TWN":"你瘋啦！萬一她口袋裡放的是手榴彈怎麼辦！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"경계하시는 건 상관없지만, 이대로는 두 분 입장이 곤란해질 텐데요.","JPN":"警戒するのはわかりますが、このままではお二人が困ることになりますよ。","ENG":"It makes no difference to me what you do, but you guys might be in trouble at this rate.","TWN":"你們要這樣懷疑我，我是無所謂，我是比較擔心你們啦～"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"대장님께서 저녁 동안 같이 지낼 말동무가 되어 달라고 부탁하셨거든요.","JPN":"隊長から夕食の間、話し相手をしてくれと頼まれていたので。","ENG":"Just to let you know, the captain requested that I keep him company this evening.","TWN":"因為是隊長找我來陪他晚上聊天的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"말동무……?","JPN":"話し相手……？","ENG":"Keep him company...?","TWN":"聊天……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"네. 남자 혼자 지내기엔 좀 쌀쌀한 계절이니까요.","JPN":"はい。男一人で過ごすには少し肌寒い時期ですからね。","ENG":"That’s right. It’s a tough time for a man to spend the night alone these days.","TWN":"沒錯，畢竟在這個季節裡，一個男人自己度過漫漫長夜會有點孤單的嘛～"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"어쩌지? 얼굴도 미인인데 진짜 아냐?","JPN":"どうする？　美人だし、本当じゃねぇか？","ENG":"What should we do man? I mean, she IS pretty, right?","TWN":"怎麼辦？她確實頗有姿色的，應該是真的吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"……통행증 내놔 봐. 위에 연락해서 확인해 봐야겠어.","JPN":"……通行証をよこせ。上に連絡して確認する。","ENG":"...Let me see your pass, I’ll have to call up and make sure.","TWN":"……通行證拿出來，我們跟上面的確認一下！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"어떻게 됐어? 부대에서 뭐래?","JPN":"どうだった？　部隊からは何だって？","ENG":"How did it go? What did they say?","TWN":"怎麼樣？部隊怎麼說？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"허튼 짓 말고 얼른 보내란다. 대장님이 많이 급한가 봐.","JPN":"余計なことせずに早く通せってよ。隊長が急いでるみたいだ。","ENG":"“Don’t be ridiculous and send her in now.” Guess the captain really needs her now.","TWN":"叫我們廢話少說趕快放行！隊長很急的樣子。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L12_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"에휴, 그럴 줄 알았다.","JPN":"まったく、そうだと思ったぜ。","ENG":"Ugh... I figured.","TWN":"真是的！我就知道是這樣！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"젠장. 하여튼 좀 반반하다 싶으면 죄다 침 발라 놓는다니까.","JPN":"くそ。ちょっとイケると思ったら全員唾を付けておくんだからよ。","ENG":"Damn, bro. Cute chick finally appears and the captain already snatches her away.","TWN":"該死！我有不好的預感！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"자크 대장님은 관공서에 계신다. 이 대로를 그대로 따라가다 종탑을 끼고 돌면 돼.","JPN":"ジャック隊長は役所にいらっしゃる。この大通りをまっすぐ進んで鐘塔のところを曲がっていけばいい。","ENG":"Captain Jacques is in the government office. If you follow this road for a bit and go around the bell tower, you’ll see it.","TWN":"札克隊長在官署裡，你沿著這條路走，穿過鐘塔後轉彎就會看到。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"안내 고마워요. 덕분에 약속 시간에 늦진 않겠어요.","JPN":"道案内ありがとう。おかげさまで約束の時間には間に合いそうです。","ENG":"Thank you so much for the directions. Thanks to you, I won’t be late for the appointment.","TWN":"謝謝，這樣我就不會遲到了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"……야, 잠깐. 그냥 보내기엔 너무 수상해.","JPN":"……おい、待てよ。やっぱり通すには怪しすぎる。","ENG":"...Hey, Wait a second. This is a little too suspicious to just let go.","TWN":"……喂，先等一下！還是有點可疑，不能就這樣放行！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"무슨 소리야? 부대에서 확인 받았다니까?","JPN":"何言ってんだ？　部隊に確認したんだぜ？","ENG":"What are you talking about, man? We already called and confirmed it.","TWN":"你在胡說什麼？是部隊親自確認過的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"씁. 닥치고 내 말 들어 봐.","JPN":"しっ、黙って聞け。","ENG":"Psst, shut up and listen.","TWN":"噓，你安靜點，聽我的！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"우리 같은 졸병들이 저런 여자 건드릴 기회가 언제 생기겠냐.","JPN":"俺らみてぇな下っ端があんな女に手を出せる機会がいつあるっていうんだ。","ENG":"When will we ever get another chance to mess around with a girl like her?","TWN":"像我們這種小角色，哪有機會可以碰到那種女人？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"우린 순찰조야. 수상한 놈들 걸러내는 게 일이라고. 몸수색한다는 구실로 밀고 가면 돼.","JPN":"俺らは見回り組だ。怪しい奴らを選り分けるのが仕事なんだよ。身体検査を口実にすればいい。","ENG":"We’re on patrol. It’s our job to weed out suspicious people. We can just say we need to do a thorough body search.","TWN":"我們巡邏隊的工作，不就是要看有沒有可疑人物嗎？就藉口說要搜身就好啦！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"듣고 보니 구구절절 맞는 말인데……?","JPN":"確かに､言われてみれば……？","ENG":"Huh, well, every single word you said makes sense...","TWN":"聽你這麼說，好像滿有道理的……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"이봐, 잠깐 저기 골목으로 따라와라.","JPN":"おい、ちょっとあそこの路地までついてこい。","ENG":"You there, please follow us to that alley over there for a moment.","TWN":"喂，你跟我到那邊的巷子裡！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"네? 신분은 확인된 것 아니었어요?","JPN":"はい？　身元は確認されたでしょう？","ENG":"Excuse me? Didn’t you already confirm my identity?","TWN":"為什麼？剛才不是已經確認過我的身分了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"수상한 놈들은 검문하는 게 순찰조인 우리 역할이야. 잔말 말고 시키는 대로 해.","JPN":"怪しい奴らを検問するのが俺ら見回り組の仕事だ。黙って指示どおりにしろ。","ENG":"Look lady, we’re on patrol to catch suspicious characters. Don’t talk back to me and do what you’re told.","TWN":"盤查可疑人士是我們巡邏隊的工作，廢話少說，我叫你來就來！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"흐음……?","JPN":"ふうん……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_BIKE_TRAVEL","text":{"KOREA":"후훗. 무서운 분위기 안 만드셔도 돼요. 타지에서 애인 사귀기도 힘드시겠죠.","JPN":"ふふっ。そんな険悪そうにしなくてもいいですよ。よその地で恋人を作るのも大変でしょう。","ENG":"Fuu fuu. There’s no need to be so scary, gentlemen. I understand. Getting a girlfriend in the outland can be difficult, can’t it?","TWN":"呵呵，你們不用特地演這齣啦，身處異地應該很難交到女朋友吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_BIKE_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"아…… 아, 하하. 뭐야. 초짜가 아니구만.","JPN":"え……あ、はは。なんだ。素人じゃなかったか。","ENG":"Oh... Heh, ha ha. What the...? Looks like you aren’t new to this kinda thing.","TWN":"喔……哈哈哈，什麼嘛～你很懂嘛～"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"그러게 내가 뭐랬어. 이 자식아. 넌 나 때문에 횡재한 거야.","JPN":"だから言ったろ。この野郎、俺のおかげだからな。","ENG":"That’s what I was saying. Man, you hit the jackpot because of me.","TWN":"你看吧！我剛怎麼說的，被你賺到了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"자, 자. 빨리 이리로 와. 석 달 동안 사내 새끼들 땀내만 맡았더니 아주 죽겠어.","JPN":"さ、ほら。早くこっちに来い。三か月間ずっと男同士でいたから、汗臭くてしょうがなかったんだ。","ENG":"Alright. Hurry up and come this way. I’ve smelled nothing but sweaty guys for three months, it's killing me.","TWN":"那你還不快過來！我這三個月都跟一群臭男生混在一起，都快悶死我啦！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_TRAVEL","text":{"KOREA":"재촉할 필요 없어요. 전 벌써 준비되어 있거든요.","JPN":"急かさなくてもいいですよ。私はもう準備できてますから。","ENG":"There’s no need to rush, boys. I’ve come fully prepared.","TWN":"別急，我都準備好囉～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"너, 너 그 권총은……!","JPN":"お、お前、その拳銃は……！","ENG":"You, you... That pistol...!","TWN":"你…怎麼會有槍……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_TRAVEL","text":{"KOREA":"이거? 소매 속에 숨길 수 있는 특제야.","JPN":"これ？　袖に隠せる特製のやつ。","ENG":"Oh, this? It’s a convenient little thing you can hide in your sleeve.","TWN":"這個嗎？這是可以藏在袖子裡的特製品。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_TRAVEL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"컥……! 허억……!","JPN":"くっ……！　ぐうっ……！","ENG":"Ack...! Hngh...","TWN":"唔……！呃……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_TRAVEL","text":{"KOREA":"군기도 훈련 상태도 엉망이네. 딴마음을 먹었으면 몸수색부터 끝냈어야지.","JPN":"軍紀も訓練状態もだめね。下心があるなら身体検査から済ませておかないと。","ENG":"Looks like you lack discipline and training. If you had any doubts, you should have performed the body search properly.","TWN":"軍紀和訓練都很糟糕呢！在動邪念之前起碼要先搜身吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_TRAVEL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트, 응답하라.","JPN":"レヴナント、応答せよ。","ENG":"Revenant, Come in.","TWN":"亡靈，回答我！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"여기는 레버넌트. 듣고 있습니다.","JPN":"こちらレヴナント。聞いています。","ENG":"This is Revenant. I’m listening.","TWN":"我是亡靈，請說。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"방금 들린 총성은 뭐지? 설마 반군을 사살한 건가?","JPN":"さっきの銃声はなんだ？　まさか反乱軍を射殺したのか？","ENG":"What was that gunshot? You didn’t shoot a rebel, did you?","TWN":"剛剛的槍聲是怎麼回事？你將叛軍擊斃嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네. 껄떡거리는 걸 받아 주면 지각할 것 같았거든요.","JPN":"はい。これ以上付き合うと遅刻しそうでしたので。","ENG":"Yeah well, I thought I’d be late if I did things in your way.","TWN":"是，因為我擔心再拖下去會遲到。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네가 지금 있는 곳이 반군 점령지 한복판이라는 건 알고 있겠지?","JPN":"今、君の居る所が反乱軍占領地のど真ん中であることはわかっているだろうな？","ENG":"You know you’re in the middle of rebel territory, right?","TWN":"你應該知道你現在所在的位置，是叛軍佔領的重鎮吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네. 그래서 저를 생계형 꽃뱀 역할로 보내셨고요.","JPN":"はい。だから私が金目当ての女の役で送り込まれたわけですし。","ENG":"I know, I know. That's why you sent me as a hooker.","TWN":"知道，所以部長才會派我扮演蛇蠍美人的角色吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"어쩌겠나. 타깃에게 조용히 접근할 수 있는 방법이 그것뿐인데.","JPN":"仕方ないだろう。ターゲットにばれずに近づける方法がそれしかないんだ。","ENG":"Well, it is what it is. It’s the only way to approach the target quietly.","TWN":"能怎麼辦呢？這是唯一能不動聲色接近目標的方法。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"반군에 대한 자네 심정은 나도 알아. 하지만 저번처럼 또 괜한 소란 피워서 일을 망쳤다간…….","JPN":"反乱軍に対する君の気持ちはわかっている。しかし、この前のように余計な騒ぎを起こして台無しにしたら……","ENG":"Look, I know how you feel about the rebels, but if you mess things up again like last time...","TWN":"我明白你對於叛軍的感受，但萬一像上次一樣打草驚蛇，導致任務失敗……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저나 국장님이나 재판 없이 총살형이겠죠.","JPN":"私も局長も即座に銃殺刑でしょうね。","ENG":"Both of us will be quartered and shot without trial I guess.","TWN":"我或部長就會立刻遭到槍決吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……고려해 줘서 고맙군.","JPN":"……お気遣い、ありがとう。","ENG":"Please do try to be a little more careful.","TWN":"……謝謝你的顧慮。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"너무 걱정 마세요, 국장님. 타깃은 보안국까지 안전하게 모셔다 드리겠습니다.","JPN":"あまり心配しないでください、局長。ターゲットは保安局まで安全に連れていきます。","ENG":"Don’t worry, Chief. I’ll get the target to the National Security office safely.","TWN":"部長你放心，我會把目標安全帶到安全局的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 보안국 1급 공작원 레아 슈나이더\\n코드명: <color=#ffd34c>레버넌트</color>\\n반군 지도자 <color=#ffd34c>자크</color> 납치 임무 수행 중","JPN":"グロニア保安局1級工作員レア・シュナイダー\\nコードネーム：<color=#ffd34c>レヴナント</color>\\n反乱軍指導者<color=#ffd34c>ジャック</color>拉致任務遂行中","ENG":"Gronia Department of National Security’s First-class Operative Leah Schneider\\nCodename: <color=#ffd34c>Revenant</color>\\nMission: Kidnap Rebel Forces Leader <color=#ffd34c>Jacques</color>","TWN":"格羅尼亞安全局1級特務 蕾亞·修奈德\\n代號: <color=#ffd34c>亡靈</color>\\n叛軍首領<color=#ffd34c>札克</color>綁架任務執行中"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};